import{useIsomorphicLayoutEffect}from"../lib/useIsomorphicLayoutEffect.js";const useNativeFormResetListener=(t,r)=>{useIsomorphicLayoutEffect(()=>{if(t.current){const e=t.current.closest("form");if(e)return e.addEventListener("reset",r),()=>{e.removeEventListener("reset",r)}}},[t,r])};export{useNativeFormResetListener};